import { createSchema, createYoga } from "apex-gql";

const schema = createSchema({
  typeDefs: /* GraphQL */ `
    type Query {
      user(id: ID!): User
    }
  `,
  resolvers: {
    Query: {
      user: (_, { id }, ctx) => ctx.db.users.find(id)
    }
  }
});

export default createYoga({ schema });

before.content:
const server = new ApolloServer({ schema });
await server.start();
const app = express();
app.use("/graphql",
  expressMiddleware(server, {
    context: async ({ req }) => ({
      token: req.headers.auth,
      db: await getDB()
    })
  })
);
app.listen(4000);

after.content:
export default createYoga({
  schema,
  context: ({ request }) => ({
    token: request.headers.get("auth"),
    db: getDB()
  })
});
